import React, { useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { addToCart } from '../redux/cartActions';
import { useNavigate } from 'react-router-dom';
import { SERVICES_DB } from '../utils/database';
import '../styles/Services.css';

const Services = () => {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { isAuthenticated } = useSelector(state => state.auth);
  const [selectedService, setSelectedService] = useState(null);
  const [showModal, setShowModal] = useState(false);
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const handleViewDetails = (service) => {
    setSelectedService(service);
    setQuantity(1);
    setActiveTab('description');
    setShowModal(true);
    document.body.style.overflow = 'hidden';
  };

  const handleCloseModal = () => {
    setShowModal(false);
    document.body.style.overflow = 'auto';
  };

  const handleAddToCart = (service, qty = 1) => {
    if (!isAuthenticated) {
      alert('Veuillez vous connecter pour ajouter au panier');
      navigate('/login');
      return;
    }

    dispatch(addToCart({ ...service, quantity: qty }));

    // Animation de succès
    const notification = document.createElement('div');
    notification.className = 'success-notification';
    notification.innerHTML = `
      <div class="notification-content">
        <span class="notification-icon">✓</span>
        <span>${service.name} ajouté au panier !</span>
      </div>
    `;
    document.body.appendChild(notification);

    setTimeout(() => {
      notification.classList.add('show');
    }, 100);

    setTimeout(() => {
      notification.classList.remove('show');
      setTimeout(() => notification.remove(), 300);
    }, 3000);

    setShowModal(false);
    document.body.style.overflow = 'auto';
  };

  const handleReserveNow = () => {
    handleAddToCart(selectedService, quantity);
    navigate('/appointment');
  };

  return (
    <div className="services-page">
      <section className="services-section">
        <div className="section-header">
          <div className="section-badge animate-fade-in">Nos Services</div>
          <h2 className="section-title animate-slide-up">Soins dentaires de qualité supérieure</h2>
          <p className="section-subtitle animate-slide-up delay-1">
            Des traitements professionnels avec les dernières technologies médicales
          </p>
        </div>

        <div className="services-grid-new">
          {SERVICES_DB.map((service, index) => (
            <div 
              key={service.id} 
              className="service-card-new animate-card"
              style={{ animationDelay: `${index * 0.1}s` }}
            >
              <div className="service-card-top">
                <div className="service-category-badge">{service.category}</div>
                <div className="service-rating">
                  <span className="stars">⭐⭐⭐⭐⭐</span>
                  <span className="rating-text">4.9</span>
                </div>
              </div>

              <div className="service-icon-wrapper">
                <span className="service-icon-large">{service.icon}</span>
              </div>

              <h3 className="service-title-new">{service.name}</h3>
              <p className="service-description-new">{service.description}</p>

              <div className="service-info-row">
                <div className="service-info-item">
                  <span className="info-icon">⏱️</span>
                  <div className="info-content">
                    <span className="info-label">Durée</span>
                    <span className="info-text">{service.duration}</span>
                  </div>
                </div>
                {service.details?.included && (
                  <div className="service-info-item">
                    <span className="info-icon">📋</span>
                    <div className="info-content">
                      <span className="info-label">Inclus</span>
                      <span className="info-text">{service.details.included.length} éléments</span>
                    </div>
                  </div>
                )}
              </div>

              <div className="service-footer-new">
                <div className="service-price-box">
                  <span className="price-label">À PARTIR DE</span>
                  <div className="price-wrapper">
                    <span className="price-value">{service.price}</span>
                    <span className="price-currency">DH</span>
                  </div>
                </div>
                <div className="service-actions">
                  <button 
                    className="btn-outline"
                    onClick={() => handleViewDetails(service)}
                  >
                    <span className="btn-icon">👁️</span>
                    Voir détails
                  </button>
                  <button 
                    className="btn-primary-green"
                    onClick={() => handleAddToCart(service)}
                  >
                    <span className="btn-icon">+</span>
                    Ajouter
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* Modal Détails Améliorée */}
      {showModal && selectedService && (
        <div className="modal-overlay active animate-fade-in" onClick={handleCloseModal}>
          <div className="modal-detail-content animate-scale-up" onClick={(e) => e.stopPropagation()}>
            <button className="modal-close" onClick={handleCloseModal}>
              <span>×</span>
            </button>

            <div className="modal-detail-layout">
              {/* Colonne gauche */}
              <div className="modal-detail-left">
                <div className="treatment-image">
                  <div className="treatment-badge">{selectedService.category}</div>
                  <div className="treatment-icon-large">{selectedService.icon}</div>
                  <div className="image-overlay"></div>
                </div>

                {selectedService.details?.included && (
                  <div className="treatment-advantages">
                    <h3>
                      <span className="title-icon">✨</span>
                      Avantages du traitement
                    </h3>
                    <ul>
                      {selectedService.details.included.map((item, index) => (
                        <li key={index} className="advantage-item">
                          <span className="check-icon">✓</span>
                          <span>{item}</span>
                        </li>
                      ))}
                    </ul>
                  </div>
                )}

                <div className="treatment-guarantee">
                  <div className="guarantee-icon">🛡️</div>
                  <div className="guarantee-text">
                    <strong>Garantie satisfait ou remboursé</strong>
                    <p>Résultats visibles dès la première séance</p>
                  </div>
                </div>
              </div>

              {/* Colonne droite */}
              <div className="modal-detail-right">
                <div className="treatment-header-price">
                  <div className="category-badge-small">{selectedService.category}</div>
                  <div className="price-large">
                    <span className="price-label-small">À partir de</span>
                    <div className="price-display">
                      <span className="price-amount">{selectedService.price}</span>
                      <span className="price-currency-large">DH</span>
                    </div>
                  </div>
                </div>

                <h2 className="treatment-title">{selectedService.name}</h2>

                {/* Tabs Navigation */}
                <div className="tabs-navigation">
                  <button 
                    className={`tab-btn ${activeTab === 'description' ? 'active' : ''}`}
                    onClick={() => setActiveTab('description')}
                  >
                    📝 Description
                  </button>
                  <button 
                    className={`tab-btn ${activeTab === 'details' ? 'active' : ''}`}
                    onClick={() => setActiveTab('details')}
                  >
                    📊 Détails
                  </button>
                  {selectedService.details?.procedure && (
                    <button 
                      className={`tab-btn ${activeTab === 'procedure' ? 'active' : ''}`}
                      onClick={() => setActiveTab('procedure')}
                    >
                      🔬 Procédure
                    </button>
                  )}
                </div>

                {/* Tabs Content */}
                <div className="tabs-content">
                  {activeTab === 'description' && (
                    <div className="tab-panel animate-fade-in">
                      <div className="treatment-stats">
                        <div className="stat-card">
                          <div className="stat-icon">⏱️</div>
                          <div className="stat-info">
                            <span className="stat-label">Durée</span>
                            <span className="stat-value">{selectedService.duration}</span>
                          </div>
                        </div>
                        {selectedService.details?.included && (
                          <div className="stat-card">
                            <div className="stat-icon">📊</div>
                            <div className="stat-info">
                              <span className="stat-label">Séances</span>
                              <span className="stat-value">{selectedService.details.included.length}</span>
                            </div>
                          </div>
                        )}
                        <div className="stat-card">
                          <div className="stat-icon">⭐</div>
                          <div className="stat-info">
                            <span className="stat-label">Satisfaction</span>
                            <span className="stat-value">98%</span>
                          </div>
                        </div>
                      </div>

                      <div className="treatment-description-box">
                        <h3>Description du traitement</h3>
                        <p>{selectedService.description}</p>
                      </div>
                    </div>
                  )}

                  {activeTab === 'details' && (
                    <div className="tab-panel animate-fade-in">
                      <div className="treatment-details-grid-compact">
                        <div className="detail-row">
                          <span className="detail-label">Type de traitement</span>
                          <span className="detail-value">{selectedService.category}</span>
                        </div>
                        <div className="detail-row">
                          <span className="detail-label">Durée par séance</span>
                          <span className="detail-value">{selectedService.duration}</span>
                        </div>
                        {selectedService.details?.anesthesia && (
                          <div className="detail-row">
                            <span className="detail-label">Anesthésie</span>
                            <span className="detail-value">{selectedService.details.anesthesia}</span>
                          </div>
                        )}
                        {selectedService.details?.recovery && (
                          <div className="detail-row">
                            <span className="detail-label">Récupération</span>
                            <span className="detail-value">{selectedService.details.recovery}</span>
                          </div>
                        )}
                        {selectedService.details?.followUp && (
                          <div className="detail-row">
                            <span className="detail-label">Suivi recommandé</span>
                            <span className="detail-value">{selectedService.details.followUp}</span>
                          </div>
                        )}
                        <div className="detail-row">
                          <span className="detail-label">Prix total</span>
                          <span className="detail-value highlight">{selectedService.price} DH</span>
                        </div>
                      </div>
                    </div>
                  )}

                  {activeTab === 'procedure' && selectedService.details?.procedure && (
                    <div className="tab-panel animate-fade-in">
                      <div className="procedure-box">
                        <div className="procedure-icon">🔬</div>
                        <h4>Déroulement de la procédure</h4>
                        <p>{selectedService.details.procedure}</p>
                      </div>
                    </div>
                  )}
                </div>

                <div className="quantity-selector">
                  <span className="quantity-label">Quantité</span>
                  <div className="quantity-controls">
                    <button 
                      className="qty-btn"
                      onClick={() => setQuantity(Math.max(1, quantity - 1))}
                    >
                      −
                    </button>
                    <span className="qty-value">{quantity}</span>
                    <button 
                      className="qty-btn"
                      onClick={() => setQuantity(quantity + 1)}
                    >
                      +
                    </button>
                  </div>
                  <div className="total-price">
                    <span>Total:</span>
                    <span className="total-amount">{(selectedService.price * quantity).toFixed(2)} DH</span>
                  </div>
                </div>

                <div className="modal-actions">
                  <button 
                    className="btn-reserve"
                    onClick={handleReserveNow}
                  >
                    <span className="btn-icon">📅</span>
                    Réserver maintenant
                  </button>
                  <button 
                    className="btn-add-cart"
                    onClick={() => handleAddToCart(selectedService, quantity)}
                  >
                    <span className="btn-icon">🛒</span>
                    Ajouter au panier
                  </button>
                </div>

                <div className="contact-box">
                  <div className="contact-icon">💬</div>
                  <div className="contact-text">
                    <p>Des questions sur ce traitement ?</p>
                    <button className="btn-contact">Contactez-nous</button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Services;
